      function CF_20Formula return Char is

V_DURATION     VARCHAR2(50);
v_DURATION_YES VARCHAR2(1);

/*

begin
  v_DURATION_YES := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
					 0,:p_form_id,'00001','00635','00033');
	
	IF V_DURATION_YES = '1' THEN
