cursor cur_1 is
select VALUE
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )  --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '00033'               --- ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ = 1
;

cursor cur_2 is
select a.value	
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )  --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '00637'               --- ΤΟΜΕΑΣ ΕΡΓΑΣΙΑΣ = 'Ε' / 'ΕΦ' 
and   a.value	                       in ( 'Ε',  'ΕΦ' )       --- EΡΓΑΣΙΑ / ΕΡΓΑΣΙΑ ΣΕ ΦΟΡΕΙΣ ΓΕΝ/ΗΣ ΚΥΒΕΡ  (ΑΠΟ PENLOV_WORK_DOMAIN_EFKA)
;

begin
	
	
	OPEN  CUR_1;
	FETCH CUR_1 INTO v_DURATION_YES;
	CLOSE CUR_1;
	
  IF NVL(v_DURATION_YES,'0') = '1'
  	THEN 
  		OPEN  CUR_2;
			FETCH CUR_2 INTO v_DURATION;
			CLOSE CUR_2;
  END IF;
  
	return nvl(v_DURATION,'0');

END;

      function CF_21Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   A.INSTITUTION_CODE_AYTOT = :INST_CODE_AYTOT
AND   AYTOT_DA_FLG             = '1'; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   A.INSTITUTION_CODE_AYTOT = :INST_CODE_AYTOT
AND   AYTOT_DA_FLG             = '1'; 

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   A.INSTITUTION_CODE_AYTOT = :INST_CODE_AYTOT
AND   AYTOT_DA_FLG             = '1'; 

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

