      function M_51FormatTrigger return boolean is
/* CHRYS 9/6/2021 
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;

begin
  -- G?? ???GOG?S ??? ????? G?? ????S??S ???? 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;
	  
  IF V_2019 = '1' THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
end;
END CHRYS 9/6/2021 */
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;

-- CHRYS 1/7/2021
CURSOR CUR_CONV_START_DATE IS
SELECT START_dATE
FROM PEN_ACCOUNT
WHERE ACCOUNT_NO = :CP_CONV_ACCOUNT;

V_CONV_START_dATE		DATE;
-- END CHRYS 1/7/2021

begin
  -- CHRYS 1/7/2021
  OPEN	CUR_CONV_START_DATE;
  FETCH	CUR_CONV_START_DATE
  INTO  V_CONV_START_dATE ;
  CLOSE	CUR_CONV_START_DATE;
  -- END CHRYS 1/7/2021

  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	
	IF :P_IS_OGA = 1  --- ΟΤΑΝ ΥΠΑΓΩΓΗ = ΟΓΑ ΤΟΤΕ ΝΑ ΕΜΦΑΝΙΖΕΤΑΙ ΠΑΝΤΑ MAIL 19/07/2021 ΝΤ & ΤΜΗΜΑ ΝΟΜΟΘΕΣΙΑΣ ΜΗ ΜΙΣΘΩΤΩΝ
	-- CHRYS 12/7/2022 	THEN RETURN (TRUE);
		THEN RETURN (FALSE); -- CHRYS 12/7/2022
	ELSE
	  IF NVL(V_01_01_2019,'0') = '1' OR 
	  	( NVL(V_01_10_2019,'0') = '1' 
	  	AND :cp_award_TYPE != '8') -- CHRYS 9/6/2021 
	  	THEN
	  	return (FALSE);
		-- CHRYS 1/7/2021
		ELSIF NVL(V_01_10_2019,'0') = '1' AND :cp_award_TYPE = '8' AND V_CONV_START_dATE >= TO_DATE('01/01/2019','DD/MM/RRRR') THEN
	  	return (FALSE);
	 	-- END CHRYS 1/7/2021 	
	  ELSE
	  	return (TRUE);
	  END IF;
  END IF;
  
  return (TRUE);
end;

      function AfterPForm return boolean is
CURSOR C1 IS
SELECT COM_ORG_BRANCHES.BRANCH_NAME, PEN_PRODUCTS.PRODUCT_CODE, PEN_PRODUCTS.PROCUCT_DESCRIPTION, COM_ORG_BRANCHES.BRANCH_CODE
FROM REG_INSURED, 
     PEN_APPLICATION_INSTANCES, 
	   COM_ORG_BRANCHES, 
	   PEN_QC_PER_PRODINST, 
	   PEN_PRODUCT_PER_INSTITUTIONS,
	   PEN_PRODUCTS,
	   COM_PENSION_IKA_INSTITUTION
 WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE
   AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001'
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR
   AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID
   AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID
   AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST
   AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
   AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
   AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
   AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;


---- pollaples giratos / anapirias TSAY-TSMEDE ktl.  (NT - 02/12/2020)
cursor c2 is
SELECT VALUE --- (ΝΑΙ=1,ΟΧΙ=0,ΔΕΝ ΑΦΟΡΑ=2)
 FROM pen_dec_fact_types_instance
WHERE 1=1 
  AND pen_dec_fact_types_instance.ins_insured_id               = :p_insured_id 
  AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1'  
  AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR        = :P_DEC_INCR_SEC_NO_SR 
  AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR          = :p_dt_decision_year 
  AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR          = :p_dt_dec_unit_code 
  AND pen_dec_fact_types_instance.title_code                   = '00661' --ΠΟΛΛΑΠΛΗ ΣΥΝΤΑΞΗ
  AND pen_dec_fact_types_instance.dec_fact_type_code           = '00809' --ΠΟΛΛΑΠΛΗ ΣΥΝΤΑΞΗ
  ;

l_pollapli_syntaxi varchar2(12);


cursor c_wrk is 
select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid 
from wrk_decisions a
where a.status   = '1'
and   a.pen_unit = :P_DT_DEC_UNIT_CODE
and   a.pen_year = :P_DT_DECISION_YEAR
and   a.pen_no   = :P_DEC_INCR_SEC_NO
;

cursor c_nat is
SELECT COUNT(1)
 FROM PEN_QT_PER_BE_CC_PER_ACCOUNT A
WHERE A.CC_PER_BE_TYPE_PER_DECINS_UPD = '2' ---ΑΠΟΡΡΙΠΤΙΚΗ
AND   A.CP_CALCULATION_PARAMETER_CODE IN ('ETHNI','EEETB','ETHSQ','EDETH','EDAET','EEDET','EMETH','EEAET','EEEBM') -- CHECK IN PENBAT_FINAL_AMOUNT_RAISE
AND   A.ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO 
;

l_National_Exists Number := 0 ;


cursor c3 is
SELECT count(1)
 FROM PEN_EFKA_DAYS_HDR b
WHERE B.insured_id                 = :P_INSURED_ID
 AND  B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE 
 AND  B.PDTA_APPLICATION_YEAR      = :P_APPL_YEAR 
 AND  B.APPLICATION_INCR_SEQ_NO    = :P_APPL_INCR_SEQ_NO ;

lc3 Number;


cursor c_qual is
select nvl(c.qual_flg,0) 
    from pen_product_per_institutions b,
         pen_introductions            c
 where 1=1
  and  b.introduction_code            = c.introduction_code
  and  b.product_per_institution_code = :P_PRODINST
;

CURSOR cur_oga IS
SELECT 1 
FROM pen_product_per_institutions A,  
     pen_introductions B
WHERE A.introduction_code = B.introduction_code 
 AND  A.prodinst_description LIKE '%ΟΓΑ%'
 AND  A.product_per_institution_code = :P_PRODINST
; 

l_IS_OGA number := 0;
 


cursor c_E_KEYS is
SELECT a.E_DEC_NO,
       a.E_DEC_YEAR||'/'||a.E_DEC_NO||'*' ,
       a.EPIFILAKSI 
  FROM PEN_DECISION_INSTANCE a
 where dt_decision_year = :P_DT_DECISION_YEAR
  and  dec_incr_seq_no  = :P_DEC_INCR_SEC_NO
  and  dt_dec_unit_code = :P_DT_DEC_UNIT_CODE
  ;

l_dec_no VARCHAR2(100); 


L_EPIFILAKSI   VARCHAR2(1);

cursor c_Fast_Track is
select count(1) cnt
from   pen_dec_fact_types_instance a
where  a.di_document_type_dec_coce_sr = '1'  
and    a.status 			                = '1'
and    a.ins_insured_id               = :p_insured_id 
and    a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and    a.di_decision_year_sr          = :p_dt_decision_year 
and    a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and    a.title_code                   = '04921'   
and    a.dec_fact_type_code           = '04921' 
and    a.value	                       = '4'   --- 4 -fast track / 2 -non fast track    
;

cursor c_anagnoriseis is
select count(1)
  from pen_ops.Pen_Decision_Instance pdin, 
       Wrk_In_Out wiou, 
       Wrk_Application wapp, 
       Web_Wrk_Appl_EFKA wwae,
       Web_Wrk_EFKA_Cont_Work wecw, 
       Pen_Auto_Ins_Hist paih
where pdin.PAI_PDTA_Application_Unit_Code = wiou.Protocol_Orgbra_Code
   and pdin.PAI_PDTA_Application_Year      = wiou.Protocol_Year
   and pdin.PAI_Application_Incr_Seq_No    = wiou.Protocol_No
   and wiou.Ref_Appl_SID                   = wapp.Appl_SID
   and wapp.Appl_Protocol_Orgbra_Code      = wwae.Appl_Protocol_Orgbra_Code
   and wapp.Appl_Protocol_Year             = wwae.Appl_Protocol_Year               
   and wapp.Appl_Protocol_No               = to_char(wwae.Appl_Protocol_No)
   and wecw.Appl_SID                       = wwae.Appl_SID
   and paih.Call_ID                        = wecw.WS_Iah_Call_ID
   and paih.RecType                        = 5
   and pdin.Status                         = '1'
   and pdin.dt_dec_unit_code               = :P_DT_DEC_UNIT_CODE
   and pdin.dt_decision_year               = :P_DT_DECISION_YEAR
   and pdin.dec_incr_seq_no	               = :P_DEC_INCR_SEC_NO
  ;
  
l_anagnoriseis number:=0;

cursor cur_is_aytomati is
select count(1) 
from  pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status                       = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   = '00001' 
and   a.dec_fact_type_code           = '88888' 
; 

l_is_aytomati  number :=0;

cursor c_prep_Days is  ---ELEGXOS XRONON STON PREPARE DAYS GIA AYTOMATOPOIHMENES
SELECT COUNT(1)
FROM PEN_OPS.PEN_PREPARE_DAYS , 
     COM_INSURANCE_HISTORY_TYPES,
     COM_COVERS_PER_COVERAGES
WHERE  PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID          = :P_INSURED_ID 
	AND  PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE    = COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE
	AND  COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE    = PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE
	AND  COM_COVERS_PER_COVERAGES.CVR_COVER_CODE IN ('ΚΣΙ', 'ΚΣΝ')
	AND  ( nvl(NOTICE_INSURANCE_DAYS,0) != 0 OR nvl(NOTICE_INS_DAYS_INCR,0) != 0)
  AND  NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2')          = '2' 
  AND  PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE    = :P_APPL_UNIT_CODE  
  AND  PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR           = :P_APPL_YEAR  
  AND  PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO             = :P_APPL_INCR_SEQ_NO    
 ;

 
begin
  
  OPEN C1;
   FETCH C1 INTO :P_BRANCH_NAME, :P_PRODUCT_CODE, :P_PRODUCT_DESCRIPTION, :P_BRANCH_CODE;
  CLOSE C1; 
  
  open c_wrk;
	 fetch c_wrk into :P_WRK_DEC_NO;
	close c_wrk;
	
  -- ΠΟΛΛΑΠΛΕΣ ΣΥΝΤΑΞΕΙΣ ΓΙΑ ΦΥΛΛΟ ΥΠΟΛΟΓΙΣΜΟΥ 
  open c2; 
	 fetch c2 into l_pollapli_syntaxi;
	close c2; 
	
	if nvl(l_pollapli_syntaxi,'0') = '1' 
  	then 
  	:P_POLLAPLI_SYNTAXI := 1;
  else
    :P_POLLAPLI_SYNTAXI := 0;
  end if;  
  
	-- ΗΜΙΑΥΤΟΜΑΤΗ ΑΠΟΝΟΜΗ 	
  OPEN c_nat;
   FETCH c_nat INTO l_National_Exists;
  CLOSE c_nat; 

  IF NVL(l_National_Exists,0) > 0 
  	THEN :P_HMIAYTOMATH := 1;
    ELSE :P_HMIAYTOMATH := 0;
  END IF; 	
  
  -- ΗΜΕΡΕΣ ΑΛΛΩΝ ΦΟΡΕΩΝ 
  open c3; 
	 fetch c3 into lc3;
	close c3; 
	if nvl(lc3,0) >= 1 
	  then :p_application_efka_days := 1;
	  else :p_application_efka_days := 0;
	end if; 

  -- ΘΕΜΕΛΙΩΝΕΙ ? 
	open c_qual;
	 fetch c_qual into :P_QUAL_FLG;
	close c_qual; 

  -- ΕΙΝΑΙ ΟΓΑ Η ΥΠΑΓΩΓΗ?
  open cur_oga;
   fetch cur_oga into l_IS_OGA ;
  close cur_oga;
   
  IF ( :P_PRODINST IN ( '1352','21352','1353','1224','11352','1202','3353','1353','21352','1224','3353','4353','21352','4353',
                        '1353','1224','1436','11352','1202','1352','11352','1202',
                        '22352' -- CHRYS 20/7/2022
                        ) or l_IS_OGA = 1 )
  THEN :P_IS_OGA := 1;
  ELSE :P_IS_OGA := 0;
  END IF;	
  
  open  cur_is_aytomati;
  fetch cur_is_aytomati into l_is_aytomati;
  close cur_is_aytomati;
  
  -- ΑΥΤΟΜΑΤΗ ΑΠΟΦΑΣΗ ΜΕ ΗΛΕΚΤΡΟΝΙΚΗ ΥΠΟΓΡΑΦΗ
  open  c_E_KEYS;
	fetch c_E_KEYS into l_dec_no, :p_e_yyyyaa, L_EPIFILAKSI; 
	close c_E_KEYS;
		
 	if nvl(L_EPIFILAKSI,'0') = '9' 
 		then 
 		:P_SHOW_E_SIGN := 1;
 		:P_ANATHER_DIMOSIOU := 'Η απόφαση εκδίδεται σύμφωνα με τις διατάξεις του ν. 4921/2022 (ΦΕΚ 75, Α'' 18/04/2022) και την αριθμ.40066/03-05-2022 (ΦΕΚ 2152, Β'' 03/05/2022) Απόφαση του Υπουργού Εργασίας & Κοινωνικών Υποθέσεων';	
 	end if;
 	
 	
	if l_dec_no is not null then 
	   :p_e_yyyyaa :=	'*e-'||:p_e_yyyyaa;
	else
	 	 :p_e_yyyyaa := null;
	end if;	 
	
	-- FAST_TRACK ΑΥΤΟΜΑΤΩΝ ΑΠΟΦΑΣΕΩΝ
  open  c_Fast_Track;
	fetch c_Fast_Track into :P_FAST_TRACK;
	close c_Fast_Track;
 
  -- ΕΠΙΦΥΛΑΞΗ ΑΠΟ ΑΥΤΟΜΑΤΕΣ ΑΠΟΦΑΣΕΙΣ
  if l_dec_no is not null or nvl(l_is_aytomati,0) > 0 then
  	:p_is_aytomati := 1;
  end if;
  	
  
		
		--- 23/08/2022 ΟΤΑΝ ΕΚΔΙΔΟΝΤΑΙ ΑΥΤΟΜΑΤΟΠΟΙΗΜΕΝΕΣ ΑΠΟΦΑΣΕΙΣ ΜΕ ΑΝΑΓΝΩΡΙΣΕΙΣ ΘΑ ΕΜΦΑΝΙΖΕΤΑΙ ΣΥΓΚΕΚΡΙΜΕΝΟ ΚΕΙΜΕΝΟ ΣΤΟ ΔΙΑΤΑΚΤΙΚΟ -MAIL ΑΠΟ 22/08/2022 PDROUVAS+ΑΒΑΛΙΑΝ+ΑΜΕΤΑΧΑ
	  open  c_anagnoriseis;
	  fetch c_anagnoriseis into l_anagnoriseis;
	  close c_anagnoriseis;
	  
	  
	  
	  if nvl(l_anagnoriseis,0) > 1 
	  	then :P_anagnoriseis := 1; 
	    else :P_anagnoriseis := 0;
	  end if; 	
	  
	  
--	  SRW.MESSAGE(100,' :P_anagnoriseis :'|| :P_anagnoriseis);
--	  SRW.MESSAGE(100,' :P_FAST_TRACK :'|| :P_FAST_TRACK);	                                                     
--    SRW.MESSAGE(100,' :L_EPIFILAKSI :'|| L_EPIFILAKSI);
	  
	  if NVL(:P_anagnoriseis,0) > 0 
	    then :p_epifylaxi := 'Επιφυλασσόμεθα για την τροποποίηση της παρούσας απόφασης ως προς τον χρόνο ασφάλισης '||chr(10)||
	                         ' που θα προκύψει απο την έκδοση αναγνωριστικής απόφασης, καθώς επίσης και για τον τρόπο '||chr(10)||
	                         ' αποπληρωμής του νέου ασφαλιστικού χρόνου.';
	  else
	  		if l_epifilaksi = '1' then
		    :p_epifylaxi := 'Επιφυλασσόμεθα για τυχόν αναθεώρηση της παρούσας απόφασης μετά απο επανεξέταση στοιχείων της   '||
		                    ' συνταξιοδοτικής σας περιπτώσης';
	  		else
	  		:p_epifylaxi := null;	
		    end if;	
	  end if;	
			
  IF :p_dt_dec_unit_code  = '09930' THEN
  	:P_NOTES := 'Κατά της απόφασης αυτής μπορείτε να ασκήσετε έφεση ενώπιον του Αρμοδίου Τμήματος '||
  	            'του Ελεγκτικού Συνεδρίου εντός 60 ημερών (ν.4700/2020 άρθρα 111, 113, 352 & 354) '||
  	            'από την κοινοποίησή της. Σε κάθε περίπτωση η κοινοποίηση θεωρείται ότι έγινε την '||
  	            'εξηκοστή μέρα από την ημερομηνία που αναγράφεται στην απόφαση αυτή. ' ;
  END IF;	
  	
  IF :p_dt_dec_unit_code  = '09932' THEN
  	:P_NOTES := 'Αν για οποιονδήποτε λόγο δεν συμφωνείτε με το περιεχόμενο της ανωτέρω Πράξης, μπορείτε '||
  	            'να ασκήσετε κατ'' αυτής έφεση ενώπιον του Αρμοδίου Τμήματος του Ελεγκτικού Συνεδρίου εντός 60 ημερών '||
  	            '(ν.4700/2020 άρθρα 111,113, 352 & 354) από την κοινοποίηση του εγγράφου. Η κοινοποίηση της πράξης '||
  	            'θεωρείται ότι έγινε την εξηκοστή μέρα από την ημερομηνία που φέρει το έγγραφο αυτό. ' ;
  END IF;	
  
   -- ΕΡΓΑΣΙΑ ΜΕΤΑ ΤΟ 2024
  :P_ERGASIA_2024 := CHECK_ERGASIA_2024(:P_INSURED_ID,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR);

  
  -- ΣΗΜΕΙΩΣΕΙΣ
  :P_NOTES := PEN_OPS.f_Get_Pen_Reports_Notes(:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_PRODUCT_CODE);
  
    -- ΕΛΕΓΧΟΣ ΧΡΟΝΩΝ PREPARE DAYS
  open c_prep_Days;
	 fetch c_prep_Days into :P_HAS_PREPARE_PROTOCOLS; 
	close c_prep_Days;
	
  return (TRUE);
end;

function CF_ERGASIAFormula return Char is
cursor cur_synexisi_ergasias is select count(1) from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code in ( '00635','01635' ) --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016) and a.dec_fact_type_code = '00033' --- ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ = 1 and a.value = '1' --- 1-YES / 0-NO ;
cursor cur_ergasia is select decode(a.value , 'Ε' , 'Το μεικτό ποσό της σύνταξης που δικαιούται ο ασφαλισμένος, ως εργαζόμενος συνταξιούχος, θα πρέπει να μειωθεί '||chr(10)|| 'κατά 30% εφόσον για την εργασία / αυτοαπασχόλησή του υπάρχει υποχρέωση υπαγωγής στην ασφάλιση του e-ΕΦΚΑ' , 'ΕΦ', 'Η καταβολή του ποσού της σύνταξης που δικαιούται ο ασφαλισμένος σύμφωνα με την απόφαση αυτή, αναστέλλεται κατά '||chr(10)|| 'το χρονικό διάστημα που παρέχει εργασία σε Φορέα Γενικής Κυβέρνησης, για την οποία υπάρχει υποχρέωση υπαγωγής '||chr(10)|| 'στην ασφάλιση του e-ΕΦΚΑ, και μέχρι τη συμπλήρωση του 61ου / 62ου έτους της ηλικίας του, σύμφωνα με τις οικείες '||chr(10)|| 'διατάξεις του άρθρου 27 του Ν.4670/2020, όπως ισχύει.' ) txt from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code in ( '00635','01635' ) --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016) and a.dec_fact_type_code = '00637' --- ΤΟΜΕΑΣ ΕΡΓΑΣΙΑΣ = 'Ε' / 'ΕΦ' and a.value in ( 'Ε', 'ΕΦ' ) --- EΡΓΑΣΙΑ / ΕΡΓΑΣΙΑ ΣΕ ΦΟΡΕΙΣ ΓΕΝ/ΗΣ ΚΥΒΕΡ (ΑΠΟ PENLOV_WORK_DOMAIN_EFKA) union all select 'Ο ασφαλισμένος εμπίπτει σε μία από τις εξαιρέσεις της παρ. 4 του Ν. 4670/2020, όπως ισχύει, και για το λόγο '||chr(10)|| 'αυτό το ποσό που αναγνωρίζεται με την απόφαση αυτή, παραμένει αμετάβλητο κατά το χρονικό διάστημα '||chr(10)|| 'της εργασίας / αυτοαπασχόλησής τους' txt from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code in ( '00635','01635' ) --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016) and a.dec_fact_type_code = '01676' --- ΕΞΑΙΡΕΣΕΙΣ ΕΡΓΑΣΙΑΣ ΤΟΥ Ν.4670/2020 (ΑΠΟ PPILOV_WORK_DOMAIN_EXCEPTION) ;
l_synexisi_ergasias number := 0; l_cur_ergasia varchar2(2000) := ''; l_string_out varchar2(2000) := '';
begin
open cur_synexisi_ergasias; fetch cur_synexisi_ergasias into l_synexisi_ergasias; close cur_synexisi_ergasias;
if nvl(l_synexisi_ergasias,0) > 0 then
for x in cur_ergasia loop l_cur_ergasia := x.txt; l_string_out := l_string_out||chr(10)||l_cur_ergasia||chr(10); end loop;
-- το κειμενο για την εργασια εμφανιζεται μονο μετα τις 28/2/2020 που εφαρμοζεται ο ν.4670/2020 και για γηρατος μονο if :P_FACTITIOUS_DATE >= to_date('28/02/2020','dd/mm/yyyy') and :P_PRODUCT_CODE = '00001' then if l_string_out is not null then :cp_keimeno_ergasias := 'ΕΠΕΙΔΗ Ο ΑΣΦΑΛΙΣΜΕΝΟΣ ΕΧΕΙ ΔΗΛΩΣΕΙ ΟΤΙ ΕΡΓΑΖΕΤΑΙ/ΑΥΤΟΑΠΑΣΧΟΛΕΙΤΑΙ ΚΑΤΑ ΤΗΝ ΗΜΕΡΟΜΗΝΙΑ ΥΠΟΒΟΛΗΣ ΤΗΣ '||chr(10)|| 'ΑΙΤΗΣΗΣ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ ΘΑ ΠΡΕΠΕΙ ΝΑ ΕΦΑΡΜΟΣΤΟΥΝ ΟΙ ΔΙΑΤΑΞΕΙΣ ΤΟΥ ΑΡΘΡΟΥ 20 ΤΟΥ Ν.4387/2016, ΟΠΩΣ '||chr(10)|| 'ΤΡΟΠΟΠΟΙΗΘΗΚΕ ΚΑΙ ΙΣΧΥΕΙ ΜΕ ΤΟ ΑΡΘΡΟ 27 ΤΟΥ Ν.4670/2020 '; end if;
return(l_string_out); else return ' '; end if;
else
return null;
end if;
exception when others then return null;
end;

function CF_XRONOS_THEMELIOSISFormula return Char is
cursor cur_hmeres_MH_misthoton is select 'HMEΡΕΣ : '||a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01632' --- ΣΤΟΙΧΕΙΑ ΕΘΝΙΚΗΣ ΣΥΝΤΑΞΗΣ and a.dec_fact_type_code = '00647' --- ΗΜΕΡΕΣ ΑΣΦΑΛΙΣΗΣ (ΜΗ MΙΣΘΩΤΩΝ) ;
cursor cur_xronos_misthoton is select 'HMEΡΕΣ : '||a.value final_value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01632' --- ΣΤΟΙΧΕΙΑ ΕΘΝΙΚΗΣ ΣΥΝΤΑΞΗΣ and a.dec_fact_type_code = '00642' --- ΗMEΡΕΣ ΑΣΦΑΛΙΣΗΣ (ΜΙΣΘΩΤΩΝ) UNION select 'ΜΗΝΕΣ : '||a.value final_value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01632' --- ΣΤΟΙΧΕΙΑ ΕΘΝΙΚΗΣ ΣΥΝΤΑΞΗΣ and a.dec_fact_type_code = '00641' --- MHNEΣ ΑΣΦΑΛΙΣΗΣ (ΜΙΣΘΩΤΩΝ) UNION select 'ETH : '||a.value final_value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01632' --- ΣΤΟΙΧΕΙΑ ΕΘΝΙΚΗΣ ΣΥΝΤΑΞΗΣ and a.dec_fact_type_code = '00640' --- ΕΤΗ ΑΣΦΑΛΙΣΗΣ (ΜΙΣΘΩΤΩΝ) ;
l_cur_hmeres_MH_misthoton varchar2(2000) := ''; l_cur_xronos_misthoton varchar2(2000) := ''; l_string_out varchar2(2000) := '';
begin
---- ΑΝ ΘΕΜΕΛΊΩΝΕΙ ΤΟΤΕ ΣΤΕΙΛΕ ΤΙΣ ΜΕΡΕΣ ΑΠΟ PEN_ACCOUNT
IF NVL(:P_QUAL_FLG,'0') = '1' THEN
l_string_out := nvl(:p_required_days,'0');
ELSE
open cur_hmeres_MH_misthoton; fetch cur_hmeres_MH_misthoton into l_cur_hmeres_MH_misthoton; close cur_hmeres_MH_misthoton;
if l_cur_hmeres_MH_misthoton is not null then l_string_out := l_cur_hmeres_MH_misthoton; return(l_string_out); else for x in cur_xronos_misthoton loop l_cur_xronos_misthoton := x.final_value; l_string_out := l_string_out||' '||l_cur_xronos_misthoton; end loop; return(l_string_out); end if;
END IF; return(l_string_out); exception when others then return nvl(:p_required_days,'0'); ---null;
--- αν δε βρεις απο τις ειδικες πληροφοριες τοτε φερε οτι εχει γεμισει απο την οθονη των απονομων απο pen_account.number_of_days για θεμελιωση
end;

