      function CF_POSA_AYTOTELOUSFormula return Number is

cursor c_sum_posa is
select 
       -- ΑΥΤΟΤΕΛΗ 
       SUM(decode(a.cp_calculation_parameter_code, 'ETHAF', nvl(a.amount,0), 0)) aytotelis_ethniki , --ΕΘΝΙΚΗ
       SUM(decode(a.cp_calculation_parameter_code, 'ANTAF', nvl(a.amount,0),'ANSNA', nvl(a.amount,0), 0)) aytotelis_adapod, -- ΑΝΤΑΠΟΔΟΤΙΚΗ
       -- ΔΙΑΔΟΧΙΚΑ 
       SUM(decode(a.cp_calculation_parameter_code, 'ETHSQ', nvl(a.amount,0), 0)) diadoxiki_ethniki , --ΕΘΝΙΚΗ
       SUM(decode(a.cp_calculation_parameter_code, 'ANTSQ', nvl(a.amount,0),'ANSNH', nvl(a.amount,0), 0)) diadoxiki_adapod -- ΑΝΤΑΠΟΔΟΤΙΚΗ
  from pen_qt_per_be_cc_per_account a
  where  1=1   
   and a.acc_account_no = :P_ACC_ACCOUNT_NO
   and a.status         = '1'
   ;
begin
	
	open  c_sum_posa;
	fetch c_sum_posa into :cp_ayto_ethniki, :cp_ayto_adapod, :cp_diadox_ethniki, :cp_diadox_adapod;
	close c_sum_posa;
  
  return  :cp_ayto_ethniki;
  exception when others then return 0;
end;

      function CF_SUM_POSA_AYTOTFormula return Number is
begin
  RETURN NVL(:cp_ayto_ethniki,0) + NVL(:cp_ayto_adapod,0);
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

      function CF_SUM_POSA_DIADOXFormula return Number is
begin
  RETURN NVL(:cp_diadox_ethniki,0) + NVL(:cp_diadox_adapod,0);
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

      function CF_SYMFEROTERO_POSOFormula return Char is

L_RET VARCHAR2(500);
begin
IF :P_IS_OGA > 0 THEN	
	:CP_FINAL_SYMFEROTERO := :CF_OGA_TELIKO_KATAVALOMENO;
ELSE
--	srw.message(100,'CF_SUM_POSA_AYTOT :'||:CF_SUM_POSA_AYTOT);
	--srw.message(100,'CF_SUM_POSA_DIADOX :'||:CF_SUM_POSA_DIADOX);
	 IF NVL(:CF_SUM_POSA_AYTOT,0) > NVL(:CF_SUM_POSA_DIADOX,0)
	 	THEN 
  	     :CP_SYMFEROTERO_POSO := NVL(:CF_SUM_POSA_AYTOT,0)	
  	                            -- CHRYS 10/11/2022
																+ NVL(:CF_EPIDOMA_ANIKAN,0)
																+ NVL(:CF_EPIDOMA_TYFLOT,0)
																+ NVL(:CF_EPIDOMA_NOSOY_ANIKAN,0);
																-- END CHRYS 10/11/2022
	 	     L_RET := 'ΑΥΤΟΤΕΛΗΣ  '||TO_CHAR(NVL(:CP_SYMFEROTERO_POSO,0));    --TO_CHAR(NVL(:CF_SUM_POSA_AYTOT,0));   
	  ELSE 
	 	     :CP_SYMFEROTERO_POSO := NVL(:CF_SUM_POSA_DIADOX,0)
	 	                            -- CHRYS 10/11/2022
																+ NVL(:CF_EPIDOMA_ANIKAN,0)
																+ NVL(:CF_EPIDOMA_TYFLOT,0)
																+ NVL(:CF_EPIDOMA_NOSOY_ANIKAN,0);
																-- END CHRYS 10/11/2022
	 	     L_RET := 'ΔΙΑΔΟΧΙΚΗ  '||TO_CHAR(NVL(:CP_SYMFEROTERO_POSO,0));    --TO_CHAR(NVL(:CF_SUM_POSA_DIADOX,0));   
	 END IF;
 
 ----
	 /* CHRYS 29/7/2022
	 IF NVL(:CF_SUM_POSA_AYTOT,0) > NVL(:CF_SUM_POSA_DIADOX,0) THEN
		  IF NVL(:CF_SUM_POSA_AYTOT,0) > :CP_KO_ERG  THEN
		     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_AYTOT,0);
		  ELSE
		  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
		  END IF; 
	 ELSE
		  IF NVL(:CF_SUM_POSA_DIADOX,0) > :CP_KO_ERG  THEN
		     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_DIADOX,0);
		  ELSE
		  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
		  END IF;  	
	 END IF;
	 END CHRYS 29/7/2022 */
-- CHRYS 29/7/2022


 	 IF NVL(:CF_SUM_POSA_AYTOT,0) > NVL(:CF_SUM_POSA_DIADOX,0) THEN
		  IF NVL(:CF_SUM_POSA_AYTOT,0) + NVL(:CF_55,0) > :CP_KO_ERG  THEN
		     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_AYTOT,0) 
	 	                               -- CHRYS 10/11/2022
																   + NVL(:CF_EPIDOMA_ANIKAN,0)
															     + NVL(:CF_EPIDOMA_TYFLOT,0)
																   + NVL(:CF_EPIDOMA_NOSOY_ANIKAN,0)
																   -- CHRYS 10/11/2022
		                               + NVL(:CF_55,0) - NVL(:CF_PLAFON,0) + NVL(:CF_50,0); -- CHRYS 29/3/2023
		  ELSE
		  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
		  END IF; 
	 ELSE
		  IF NVL(:CF_SUM_POSA_DIADOX,0) + NVL(:CF_55,0) > :CP_KO_ERG  THEN
		     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_DIADOX,0) 
	 	                               -- CHRYS 10/11/2022
																   + NVL(:CF_EPIDOMA_ANIKAN,0)
															     + NVL(:CF_EPIDOMA_TYFLOT,0)
																   + NVL(:CF_EPIDOMA_NOSOY_ANIKAN,0)
																   -- CHRYS 10/11/2022
		                               + NVL(:CF_55,0) - NVL(:CF_PLAFON,0) + NVL(:CF_50,0); -- CHRYS 29/3/2023
		  ELSE
		  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
		  END IF;  	
	 END IF;

-- END CHRYS 29/7/2022
	 	 
 END IF;
 RETURN L_RET; 
 
 EXCEPTION WHEN OTHERS THEN NULL; 
end;

      function CF_21_DFormula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_52_DFormula return Number is
begin
  RETURN NVL(:AVERAGE_INCOME1, :INFLATED_6);
end;

      function CF_FIND_YY_MM_DDFormula return Number is
lidaysofmonth number:= 25;


CURSOR C_TRANS_TYPE IS 
SELECT DISTINCT NVL(B.DAYS_30_FLAG,'0')--, A.TRANS_DESCR   
FROM COM_INSURANCE_HISTORY_TYPES A,
     PEN_TRANS_TYPES             B,
     PEN_INSURED_DAYS            C
WHERE C.TRANSACTION_TYPE  = B.TRANSACTION_TYPE
AND   A.TRANS_TYPE        = C.INSHISTYP_TRANS_TYPE 
AND   C.INS_INSURED_ID    = :P_INSURED_ID
AND   A.TRANS_TYPE        = :TRANS_TYPE
;

l_days_flg varchar2(1);


begin
   
 -- SRW.MESSAGE(100, ':PENSION_INST_CODE : '||:PENSION_INST_CODE);
 -- SRW.MESSAGE(100, 'P_INSURED_ID : '||:P_INSURED_ID);
 -- SRW.MESSAGE(100, 'TRANS_TYPE : '||:TRANS_TYPE);
  
	
	:CP_YEARS     := null;
  :CP_MONTHS    := null;
  :CP_DAYS      := null;
 
 

  open  C_TRANS_TYPE;
  fetch C_TRANS_TYPE into l_days_flg;
  close C_TRANS_TYPE;
  
  
  if nvl(l_days_flg,'0') = '1'
  	then lidaysofmonth := 30;  --- πχ στρατιωτικες θητειες
  	else lidaysofmonth := 25;
  end if; 
 
  -- Call the procedure
  com_util_days.convdaysinyearsmontsdays(pisumofdays   => :INSURANCE_DAYS,
                                         pidaysofmonth => lidaysofmonth,
                                         poyears       => :CP_YEARS,
                                         pomonths      => :CP_MONTHS,
                                         podays        => :CP_DAYS);
	

  return (:CP_YEARS);


exception when others then return null;

  	
end;

