      function CF_OGA_TELIKH_KYRIAFormula return Number is
/* CHRYS 3/2/2023
L_RET NUMBER := 0;
begin
  -- CHRYS 6/7/2022 L_RET := (:CF_KYRIA_OGA + GREATEST(:CS_SUM_OGA_BEST_PART_AMNT,:CP_OGA_TMHMATIKO));
  L_RET := GREATEST (NVL(:CF_KYRIA_OGA,0) + NVL(:CS_SUM_OGA_BEST_PART_AMNT,0),NVL(:CP_OGA_TMHMATIKO,0) + NVL(:CS_SUM_OGA_BEST_PART_AMNT,0));
