  FETCH CUR_OGA_TELIKH_KYRIA
  INTO V_AMT;
  CLOSE CUR_OGA_TELIKH_KYRIA;
  
  RETURN V_AMT; 
end;

      function CF_OGA_POSO_20Formula return Number is

cursor c_posa is
select a.theorhtiko_amount,
       a.tmhmatiko_amount,
       a.oga_days,
       a.total_days
