      function CF_XRONOIFormula return Char is
v_date_char varchar2(10);


begin
	
  v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR,
                                             :P_DT_DEC_UNIT_CODE,
                                             :P_DEC_INCR_SEC_NO_SR, 
                                             '1',
                                             0,
                                             :p_form_id,
                                             '00001',
                                             '01632',
                                             '00647');
  
  
  IF v_date_char IS NOT NULL
  	THEN return v_date_char;
    ELSE return :P_REQUIRED_DAYS;
  END IF;	
    
 EXCEPTION WHEN OTHERS THEN RETURN NULL;

end;

